/* BTKbd — keyboard key badge.
   Figma: D-Kbd node 2637:2613 (web only — no Flutter equivalent).
   Shared between @btech/ui-vue and @btech/ui-react — keep these files identical. */

.bt-kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 16px;
  min-width: 16px;
  border-radius: var(--radius-xs);
  background: var(--bg-subtle);
  padding: 0 var(--space-2xs);
  pointer-events: none;
  user-select: none;
  vertical-align: middle;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-2xs);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
  white-space: nowrap;
}

/* Icon variant — equal padding on all sides */
.bt-kbd--icon {
  padding: var(--space-2xs);
}

/* Dark variant — component-specific bg hardcoded (no semantic light-mode token) */
.bt-kbd--dark {
  /* Raw hex allowed (CLAUDE.md §2) — neutral/700, no semantic token maps to this in light mode */
  background: #3c4450;
  color: var(--text-tertiary);
}

/* Group — horizontal row of kbd badges */
.bt-kbd-group {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2xs);
}

export type BTKbdVariant = 'text' | 'icon';

export interface BTKbdProps {
  variant?: BTKbdVariant;
  dark?: boolean;
}

export interface BTKbdGroupProps {
  // intentionally empty — group is a layout-only wrapper
}

export { default as BTKbd } from './BTKbd.vue';
export { default as BTKbdGroup } from './BTKbdGroup.vue';
export type { BTKbdProps, BTKbdGroupProps, BTKbdVariant } from './BTKbd.types';
